import java.util.*;
import java.lang.*;
import java.io.*;

class Codechef {
    // Method to check if 'm' is a subsequence of 'w'
    static boolean checkSub(String m, String w) {
        int l1 = m.length();
        int l2 = w.length();
        int i = 0, j = 0;

        while (i < l1 && j < l2) {
            if (m.charAt(i) == w.charAt(j)) {
                i++;
            }
            j++;
        }

        return (i == l1);
    }

    public static void main(String[] args) throws java.lang.Exception {
        Scanner scanner = new Scanner(System.in);

        int t = scanner.nextInt(); // Read number of test cases
        while (t-- > 0) {
            String m = scanner.next(); // Read first string
            String w = scanner.next(); // Read second string

            // Check if either string is a subsequence of the other
            if (checkSub(m, w) || checkSub(w, m)) {
                System.out.println("YES");
            } else {
                System.out.println("NO");
            }
        }

        scanner.close();
    }
}

