const fs = require('fs');

// Helper function to check if shortStr is a subsequence of longStr
function isSubsequence(shortStr, longStr) {
    let i = 0; // Pointer for shortStr
    let j = 0; // Pointer for longStr

    while (i < shortStr.length && j < longStr.length) {
        if (shortStr[i] === longStr[j]) {
            i++; // Match found, move to the next character in shortStr
        }
        j++; // Always move to the next character in longStr
    }

    // If we've traversed all characters in shortStr, it's a valid subsequence
    return i === shortStr.length;
}

function solve() {
    // Read all input from standard input (file descriptor 0)
    const input = fs.readFileSync(0, 'utf-8').trim().split(/\s+/);

    // Handle empty input edge case
    if (input.length === 0 || input[0] === '') return;

    const T = parseInt(input[0], 10);
    let currentIdx = 1;
    const results = [];

    for (let t = 0; t < T; t++) {
        const M = input[currentIdx++];
        const W = input[currentIdx++];

        let possible = false;

        // Always check the shorter string against the longer string
        if (M.length <= W.length) {
            possible = isSubsequence(M, W);
        } else {
            possible = isSubsequence(W, M);
        }

        results.push(possible ? "YES" : "NO");
    }

    // Print all results efficiently joined by newline
    console.log(results.join('\n'));
}

solve();
